parameters.functionCode:
// Extract key automation logic from Dify repository
// System Purpose: LLM app development platform with workflow, RAG, agents, and observability
// Primary Functions:
// 1. Workflow orchestration and execution
// 2. RAG pipeline management
// 3. Agent capability coordination
// 4. Model management across providers
// 5. Observability and tracing (OpenTelemetry, Langfuse, Opik, Arize Phoenix)
// 6. Application logging and monitoring

return {
  system: 'Dify LLM Platform',
  capabilities: [
    'AI Workflow Building',
    'RAG Pipeline Execution',
    'Agent Management',
    'Multi-Model Support (GPT, Mistral, Llama3, etc)',
    'OpenTelemetry Integration',
    'Trace Management',
    'Application Monitoring',
    'Message Logging',
    'Dataset Management'
  ],
  deployment: {
    containerized: true,
    docker_compose: true,
    kubernetes_ready: true,
    self_hosted: true,
    cloud: 'https://cloud.dify.ai'
  },
  core_services: [
    'API Backend',
    'Web Frontend',
    'PostgreSQL Database',
    'Redis Cache',
    'Vector Database (Weaviate/Milvus/etc)',
    'Celery Worker',
    'Scheduler (Beat)'
  ]
};

// Extract automation workflows from Dify documentation
// Key Automations Identified:

const automations = {
  workflow_execution: {
    description: 'Execute AI workflows on visual canvas',
    inputs: ['workflow_config', 'input_data'],
    outputs: ['execution_result', 'logs'],
    trigger: 'webhook_or_schedule'
  },
  rag_pipeline: {
    description: 'Document ingestion and retrieval pipeline',
    steps: [
      'document_upload',
      'text_extraction',
      'embedding_generation',
      'vector_storage',
      'semantic_search'
    ]
  },
  agent_execution: {
    description: 'Agent-based task execution with tools',
    capabilities: [
      'llm_function_calling',
      'react_pattern',
      'tool_integration',
      'reasoning_loop'
    ]
  },
  observability: {
    description: 'Application monitoring and tracing',
    services: [
      'OpenTelemetry_export',
      'Langfuse_integration',
      'Opik_tracing',
      'Arize_Phoenix_monitoring'
    ]
  },
  model_management: {
    description: 'Multi-provider LLM integration',
    providers: [
      'OpenAI',
      'Mistral',
      'Llama',
      'Custom_OpenAI_compatible'
    ]
  }
};

return automations;

// Process and transform Dify API responses
const workflows = $input.all()[0].json;
const apps = $input.all()[1].json;
const messages = $input.all()[2].json;

const processed = {
  total_workflows: workflows?.data?.length || 0,
  total_apps: apps?.data?.length || 0,
  total_messages: messages?.data?.length || 0,
  workflows: workflows?.data || [],
  apps: apps?.data || [],
  messages: messages?.data || [],
  timestamp: new Date().toISOString()
};

return processed;

// Generate observability trace data structure
const traceData = {
  service_name: 'dify',
  signals: {
    traces: {
      workflow_runs: {
        span_type: 'dify.workflow.run',
        includes: ['workflow_id', 'status', 'duration', 'model_calls']
      },
      node_execution: {
        span_type: 'dify.node.execution',
        includes: ['node_id', 'node_type', 'input', 'output', 'duration']
      },
      message_events: {
        span_type: 'dify.message',
        includes: ['message_id', 'content', 'tokens', 'cost']
      }
    },
    metrics: {
      workflow_counter: 'dify.workflow.total',
      message_counter: 'dify.message.total',
      token_counter: 'dify.tokens.total',
      error_counter: 'dify.errors.total'
    },
    logs: {
      structured: true,
      includes_trace_id: true,
      includes_span_id: true,
      content_gating: 'configurable'
    }
  },
  otel_endpoint: process.env.ENTERPRISE_OTLP_ENDPOINT || 'http://localhost:4318',
  sampling_rate: parseFloat(process.env.ENTERPRISE_OTEL_SAMPLING_RATE || '1.0')
};

return traceData;

// Aggregate and summarize automation findings
const summary = {
  platform: 'Dify LLM Application Development',
  automation_patterns: [
    {
      name: 'Workflow Orchestration',
      type: 'Event-driven',
      trigger: 'User action / Schedule / Webhook',
      processing: 'Visual workflow execution with node dependencies',
      output: 'Workflow result + execution logs'
    },
    {
      name: 'RAG Document Pipeline',
      type: 'Batch Processing',
      trigger: 'Document upload / Schedule',
      processing: 'Extract → Embed → Store → Retrieve',
      output: 'Indexed vectors + retrieval results'
    },
    {
      name: 'Agent Task Execution',
      type: 'Agentic Loop',
      trigger: 'User input / API call',
      processing: 'LLM reasoning + tool invocation + result evaluation',
      output: 'Agent response + tool call logs'
    },
    {
      name: 'Observability Pipeline',
      type: 'Continuous Monitoring',
      trigger: 'Application events',
      processing: 'Span generation → Log correlation → Metric aggregation',
      output: 'OpenTelemetry signals → OTLP export'
    }
  ],
  deployment_architectures: [
    'Docker Compose (local)',
    'Kubernetes (HA)',
    'AWS / Azure / GCP (managed)'
  ],
  key_integrations: [
    '50+ LLM providers',
    'Vector databases (Weaviate, Milvus, PGVector)',
    'Observability backends (Langfuse, Opik, Arize Phoenix, OTEL)',
    'Storage systems (S3, Azure Blob, local)'
  ],
  api_endpoints: [
    '/api/v1/workflows',
    '/api/v1/apps',
    '/api/v1/messages',
    '/api/v1/datasets',
    '/api/v1/models'
  ]
};

return summary;
